import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface GrowthTrend {
  month: string;
  value: number;
}

interface WidgetData {
  monthlyRecurringRevenue: number;
  churnRate: number;
  growthTrend: GrowthTrend[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const { monthlyRecurringRevenue, churnRate, growthTrend } = response.data as WidgetData;
  const { primaryColor } = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2D2D2D' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFFFFF' }}>
              Monthly Recurring Revenue
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              ${monthlyRecurringRevenue.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FFFFFF' }}>
              Churn Rate: {churnRate}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: growthTrend.map((d) => d.value),
                  color: primaryColor,
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: growthTrend.map((d) => d.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'revenue' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="revenue"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
